const trafficLightMachine = {
  initial: 'red',
  states: {
    red: {
      on: { NEXT: 'green' }
    },
    green: {
      on: { NEXT: 'yellow' }
    },
    yellow: {
      on: { NEXT: 'red' }
    }
  }
};

// Uso
