// State Machine Complexa
const orderMachine = {
  initial: 'idle',
  states: {
    idle: {
      on: { ADD_ITEM: 'cart' }
    },
    cart: {
      on: {
        CHECKOUT: 'checkout',
        REMOVE_ALL: 'idle'
      }
    },
    checkout: {
      on: {
        PAY: 'payment',
        CANCEL: 'cart'
      }
    },
    payment: {
      on: {
        SUCCESS: 'confirmed',
        FAIL: 'checkout'
      }
    },
    confirmed: {
      type: 'final'
    }
  }
};

// Actions e Guards
const loginMachine = {
  initial: 'idle',
  states: {
    idle: {
      on: { SUBMIT: 'loading' }
    },
    loading: {
      invoke: {
        src: 'loginService',
        onDone: 'success',
        onError: 'error'
      }
    },
    success: {
      type: 'final'
    },
    error: {
      on: { RETRY: 'loading' }
    }
  }
};

// Guards
const guardedMachine = {
  initial: 'idle',
  states: {
    idle: {
      on: {
        SUBMIT: {
          target: 'loading',
          cond: 'isValidForm'
        }
      }
    }
  }
};
